<section class="portal-page narrow"><div class="portal-head"><div><span class="eyebrow">APPOINTMENT <?=e($appointment['appointment_number'])?></span><h1>Reschedule Appointment</h1><p><?=e($appointment['doctor_name'])?> • Current: <?=date('d M Y, h:i A',strtotime($appointment['appointment_date'].' '.$appointment['appointment_time']))?></p></div><a class="btn outline" href="<?=url('appointment?id='.$appointment['id'])?>">Go Back</a></div><form class="hospital-form" method="get" action="<?=url('appointment/reschedule')?>"><input type="hidden" name="id" value="<?=$appointment['id']?>"><label>New appointment date<input type="date" name="date" min="<?=date('Y-m-d')?>" value="<?=e($selectedDate)?>" required></label><button class="btn outline">Check Available Times</button></form><form class="hospital-form" method="post" action="<?=url('appointment/reschedule')?>"><?=csrf_field()?><input type="hidden" name="id" value="<?=$appointment['id']?>"><input type="hidden" name="appointment_date" value="<?=e($selectedDate)?>"><h2>Choose a new time</h2><div class="slot-grid"><?php foreach($slots as$s):?><label class="slot"><input type="radio" name="appointment_time" value="<?=e($s['start_time'])?>" required><span><?=date('h:i A',strtotime($s['start_time']))?></span></label><?php endforeach;?></div><?php if(!$slots):?><div class="empty">No available slots on this date.</div><?php endif;?><small class="field-error"><?=e($errors['appointment_time'][0]??'')?></small><?php if($slots):?><button class="btn">Confirm New Schedule</button><?php endif;?></form></section>
